	}
	if pm.match("/Users/me/project/main.go") {
		t.Fatal("expected no match for project file")
	}
}

func TestPathMatch_ProjectRootPrefix(t *testing.T) {
	// /path means relative to project root
	pm := newPathMatcher(
		"/Users/me/project",
		"/Users/me",
