package rules

import (
	"path/filepath"
	"strings"

	"github.com/bmatcuk/doublestar/v4"
)

// pathMatcher handles gitignore-style path matching with support for:
//   - //path  → absolute filesystem path
//   - ~/path  → relative to home directory
//   - /path   → relative to project root
//   - ./path or bare path → relative to current working directory
//
// Uses doublestar for ** recursive glob matching.
type pathMatcher struct {
	// resolved is the pattern after prefix resolution to an absolute path.
	resolved string
}

// newPathMatcher creates a matcher that resolves a pattern against the given
// directory context. cwd, home, and projectRoot should be absolute paths.
func newPathMatcher(cwd, home, projectRoot, pattern string) pathMatcher {
	resolved := resolvePattern(cwd, home, projectRoot, pattern)
	return pathMatcher{resolved: resolved}
}

func (pm pathMatcher) match(filePath string) bool {
	filePath = filepath.Clean(filePath)
	matched, _ := doublestar.PathMatch(pm.resolved, filePath)
	return matched
}

// resolvePattern converts a gitignore-style pattern prefix to an absolute
// path pattern.
func resolvePattern(cwd, home, projectRoot, pattern string) string {
	switch {
	case strings.HasPrefix(pattern, "//"):
		// Absolute path: //Users/alice/file → /Users/alice/file
		return filepath.Clean(pattern[1:])
	case strings.HasPrefix(pattern, "~/"):
		// Home-relative: ~/path → /home/user/path
		return filepath.Clean(filepath.Join(home, pattern[2:]))
	case strings.HasPrefix(pattern, "/"):
		// Project-root-relative: /src → /project/src
		return filepath.Clean(filepath.Join(projectRoot, pattern[1:]))
	case strings.HasPrefix(pattern, "./"):
		// CWD-relative: ./path → /cwd/path
		return filepath.Clean(filepath.Join(cwd, pattern[2:]))
	default:
		// Bare pattern: also CWD-relative
		return filepath.Clean(filepath.Join(cwd, pattern))
	}
}

package rules

type ReadInput struct {
	FilePath string `json:"file_path"`
	Offset   int    `json:"offset,omitempty"`
	Limit    int    `json:"limit,omitempty"`
}

// ReadOpts provides directory context for resolving path patterns.
type ReadOpts struct {
	CWD         string
	Home        string
	ProjectRoot string
}

type ReadRule struct {
	decision Decision
	matchers []pathMatcher
}

// Read creates a rule that matches file read operations against gitignore-style
// path patterns. The last argument must be a ReadOpts providing directory context.
// If no patterns are given (only ReadOpts), the rule matches all reads.
func Read(decision Decision, args ...any) *ReadRule {
	patterns, opts := parsePathArgs(args)
	matchers := make([]pathMatcher, len(patterns))
	for i, p := range patterns {
		matchers[i] = newPathMatcher(opts.CWD, opts.Home, opts.ProjectRoot, p)
	}
	return &ReadRule{decision: decision, matchers: matchers}
}

func (r *ReadRule) Apply(input ReadInput) *Result {
	if len(r.matchers) == 0 {
		return NewResult(r.decision, "matches all Read operations")
	}
	for _, m := range r.matchers {
		if m.match(input.FilePath) {
			return NewResult(r.decision, "matched path pattern: "+m.resolved)
		}
	}
	return nil
}

// parsePathArgs extracts string patterns and a trailing ReadOpts from a
// variadic any slice. This allows the API: Read(Deny, "./.env", "~/.ssh/**", ReadOpts{...})
func parsePathArgs(args []any) ([]string, ReadOpts) {
	var patterns []string
	var opts ReadOpts
	for _, arg := range args {
		switch v := arg.(type) {
		case string:
			patterns = append(patterns, v)
		case ReadOpts:
			opts = v
		}
	}
	return patterns, opts
}

